SELECT FROM posts p WHERE p.is_delelte = 0 AND p.deleted_at IS NULL
AND p.status = #{status}
AND p.title LIKE CONCAT('%', #{keyword}, '%')
AND p.author_id = #{authorId}
ORDER BY p.updated_at DESC, p.id DESC

SELECT COUNT(1) FROM posts
WHERE slug = #{slug} AND is_delelte = 0 AND deleted_at IS NULL

    AND id != #{excludeId}
